// Adapt these field paths to YOUR WhatsApp provider's inbound schema.
const body = $json.body || $json;
const text = String(body.text || body.message || body.caption || '').trim();
const from = body.from || body.sender || body.author || '';
const chatId = body.chatId || body.groupId || body.chat || '';
const lower = text.toLowerCase();
const mentionedBot = lower.includes('@bot') || body.mentionedBot === true;
const parts = text.replace(/@bot/ig, ' ').split(' ').filter(Boolean);
const token = parts.find(t => t.charAt(0) === '/');
const command = token ? token.toLowerCase() : '';
const isCommand = mentionedBot && command.length > 0;
return [{ json: { isCommand, command, from, chatId, rawText: text } }];

// ⚠ PRIVATE PII BOUNDARY — phone numbers live ONLY in this node.
// Nothing downstream (this repo, Firebase, the frontend) ever receives a phone.
// Replace this static map with a private lookup (n8n data store / DB / HTTP).
const DIRECTORY = {
  // '<digits-only E.164 phone>': '<nickname>',
  // '420123456789': 'MorPet87',
};
const phone = String($json.from || '').replace(/[^0-9]/g, '');
const nickname = DIRECTORY[phone] || '';
return [{ json: { command: $json.command, chatId: $json.chatId, nickname, known: nickname.length > 0 } }];

// Turn the botCommand JSON response into a WhatsApp message.
const r = ($json.body) ? $json.body : $json;
let message;
if (r.ok) {
  message = `✅ ${r.nickname} signed in to ${r.tournament_id}.`;
} else if (r.help) {
  message = 'Available commands:\n' + (r.commands || []).map(c => `${c.name} – ${c.description}`).join('\n');
} else if (r.error === 'not_recognized') {
  message = `⚠️ ${r.message}`;
} else if (r.error === 'missing_nickname') {
  message = '⚠️ Your number is not registered for this tournament.';
} else {
  message = `⚠️ ${r.message || r.error || 'Something went wrong.'}`;
}
const chatId = $('Resolve Nickname').first().json.chatId;
return [{ json: { chatId, message } }];
